package main

import (
    "fmt"
    "sync"
    "time"
)

// ---- Fan-Out: distribute work to multiple workers ----
// ---- Fan-In: collect results from multiple workers ----

func main() {
    fmt.Println("=== Fan-Out Fan-In ===")

    // ---- Generate numbers ----
    numbers := generateNumbers(1, 10)

    // ---- Fan-Out: split work across workers ----
    ch1 := square(numbers)
    ch2 := square(numbers)
    ch3 := square(numbers)

    // ---- Fan-In: merge results ----
    results := merge(ch1, ch2, ch3)

    // ---- Collect results ----
    for result := range results {
        fmt.Println("Result:", result)
    }

    // ---- More complex fan-out fan-in ----
    fmt.Println("\n=== Complex Fan-Out Fan-In ===")

    // ---- Generate numbers with delay ----
    nums := generateNumbersWithDelay(1, 5, 50*time.Millisecond)

    // ---- Fan-Out with different work ----
    out1 := process(nums, "Worker 1")
    out2 := process(nums, "Worker 2")
    out3 := process(nums, "Worker 3")

    // ---- Fan-In ----
    merged := mergeStrings(out1, out2, out3)

    for result := range merged {
        fmt.Println(result)
    }
}

func generateNumbers(start, end int) <-chan int {
    out := make(chan int)
    go func() {
        for i := start; i <= end; i++ {
            out <- i
        }
        close(out)
    }()
    return out
}

func square(in <-chan int) <-chan int {
    out := make(chan int)
    go func() {
        for n := range in {
            time.Sleep(50 * time.Millisecond)
            out <- n * n
        }
        close(out)
    }()
    return out
}

func merge(chs ...<-chan int) <-chan int {
    var wg sync.WaitGroup
    out := make(chan int)

    output := func(ch <-chan int) {
        for n := range ch {
            out <- n
        }
        wg.Done()
    }

    wg.Add(len(chs))
    for _, ch := range chs {
        go output(ch)
    }

    go func() {
        wg.Wait()
        close(out)
    }()

    return out
}

// ---- Version with strings ----
func generateNumbersWithDelay(start, end int, delay time.Duration) <-chan int {
    out := make(chan int)
    go func() {
        for i := start; i <= end; i++ {
            time.Sleep(delay)
            out <- i
        }
        close(out)
    }()
    return out
}

func process(in <-chan int, name string) <-chan string {
    out := make(chan string)
    go func() {
        for n := range in {
            out <- fmt.Sprintf("%s: %d -> %d", name, n, n*n)
        }
        close(out)
    }()
    return out
}

func mergeStrings(chs ...<-chan string) <-chan string {
    var wg sync.WaitGroup
    out := make(chan string)

    output := func(ch <-chan string) {
        for s := range ch {
            out <- s
        }
        wg.Done()
    }

    wg.Add(len(chs))
    for _, ch := range chs {
        go output(ch)
    }

    go func() {
        wg.Wait()
        close(out)
    }()

    return out
}

