package main

import (
    "fmt"
    "sync"
)

func generate() <-chan int {
    out := make(chan int)
    go func() {
        for i := 1; i <= 10; i++ {
            out <- i
        }
        close(out)
    }()
    return out
}

func process(in <-chan int) <-chan int {
    out := make(chan int)
    go func() {
        for n := range in {
            out <- n * 2
        }
        close(out)
    }()
    return out
}

func merge(chs ...<-chan int) <-chan int {
    var wg sync.WaitGroup
    out := make(chan int)

    for _, ch := range chs {
        wg.Add(1)
        go func(c <-chan int) {
            for v := range c {
                out <- v
            }
            wg.Done()
        }(ch)
    }

    go func() {
        wg.Wait()
        close(out)
    }()

    return out
}

func main() {
    gen := generate()

    ch1 := process(gen)
    ch2 := process(gen)

    results := merge(ch1, ch2)

    for result := range results {
        fmt.Println(result)
    }
}
